1498 static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,
1499                                           Value *B, Instruction *CheckInst,
1500                                           ConstraintInfo &Info) {
1501   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");
1502 
1503   // Compute known bits for ICmpInst::compare.
1504   const DataLayout &DL = CheckInst->getDataLayout();
1505   KnownBits KnownA = computeKnownBits(A, DL);
1506   KnownBits KnownB = computeKnownBits(B, DL);
1507 
1508   auto R = Info.getConstraintForSolving(Pred, A, B);
1509   if (R.empty() || !R.isValid(Info)) {
1510     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");
1511     return ICmpInst::compare(KnownA, KnownB, Pred);
1512   }
1513 
1514   auto &CSToUse = Info.getCS(R.IsSigned);
1515 
1516   // If there was extra information collected during decomposition, apply
1517   // it now and remove it immediately once we are done with reasoning
1518   // about the constraint.
1519   for (auto &Row : R.ExtraInfo)
1520     CSToUse.addVariableRow(Row);
1521 
1522   llvm::scope_exit InfoRestorer([&]() {
1523     for (unsigned I = 0; I < R.ExtraInfo.size(); ++I)
1524       CSToUse.popLastConstraint();
1525   });
1526 
1527   if (auto ImpliedCondition = R.isImpliedBy(CSToUse)) {
1528     if (!DebugCounter::shouldExecute(EliminatedCounter))
1529       return std::nullopt;
1530 
1531     LLVM_DEBUG({
1532       dbgs() << "Condition ";
1533       dumpUnpackedICmp(
1534           dbgs(), *ImpliedCondition ? Pred : CmpInst::getInversePredicate(Pred),
1535           A, B);
1536       dbgs() << " implied by dominating constraints\n";
1537       CSToUse.dump();
1538     });
1539     return ImpliedCondition;
1540   }
1541 
1542   return ICmpInst::compare(KnownA, KnownB, Pred);
1543 }
