1656 static void
1657 removeEntryFromStack(const StackEntry &E, ConstraintInfo &Info,
1658                      Module *ReproducerModule,
1659                      SmallVectorImpl<ReproducerEntry> &ReproducerCondStack,
1660                      SmallVectorImpl<StackEntry> &DFSInStack) {
1661   Info.popLastConstraint(E.IsSigned);
1662   // Remove variables in the system that went out of scope.
