1813 static bool replaceSubOverflowUses(IntrinsicInst *II, Value *A, Value *B,
1814                                    SmallVectorImpl<Instruction *> &ToRemove) {
1815   bool Changed = false;
1816   IRBuilder<> Builder(II->getParent(), II->getIterator());
1817   Value *Sub = nullptr;
1818   for (User *U : make_early_inc_range(II->users())) {
1819     if (match(U, m_ExtractValue<0>(m_Value()))) {
1820       if (!Sub)
1821         Sub = Builder.CreateSub(A, B);
1822       U->replaceAllUsesWith(Sub);
1823       Changed = true;
1824     } else if (match(U, m_ExtractValue<1>(m_Value()))) {
1825       U->replaceAllUsesWith(Builder.getFalse());
1826       Changed = true;
1827     } else
1828       continue;
1829 
1830     if (U->use_empty()) {
1831       auto *I = cast<Instruction>(U);
1832       ToRemove.push_back(I);
1833       I->setOperand(0, PoisonValue::get(II->getType()));
1834       Changed = true;
1835     }
1836   }
1837 
1838   if (II->use_empty()) {
1839     II->eraseFromParent();
1840     Changed = true;
1841   }
1842   return Changed;
1843 }
