1873 static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
1874                                  ScalarEvolution &SE,
1875                                  OptimizationRemarkEmitter &ORE,
1876                                  TargetLibraryInfo &TLI) {
1877   bool Changed = false;
1878   DT.updateDFSNumbers();
1879   SmallVector<Value *> FunctionArgs(llvm::make_pointer_range(F.args()));
1880   ConstraintInfo Info(F.getDataLayout(), FunctionArgs);
1881   State S(DT, LI, SE, TLI);
1882   std::unique_ptr<Module> ReproducerModule(
1883       DumpReproducers ? new Module(F.getName(), F.getContext()) : nullptr);
1884 
1885   // First, collect conditions implied by branches and blocks with their
1886   // Dominator DFS in and out numbers.
1887   for (BasicBlock &BB : F) {
1888     if (!DT.getNode(&BB))
1889       continue;
1890     S.addInfoFor(BB);
1891   }
1892 
1893   // Next, sort worklist by dominance, so that dominating conditions to check
1894   // and facts come before conditions and facts dominated by them. If a
1895   // condition to check and a fact have the same numbers, conditional facts come
1896   // first. Assume facts and checks are ordered according to their relative
1897   // order in the containing basic block. Also make sure conditions with
1898   // constant operands come before conditions without constant operands. This
1899   // increases the effectiveness of the current signed <-> unsigned fact
1900   // transfer logic.
1901   stable_sort(S.WorkList, [](const FactOrCheck &A, const FactOrCheck &B) {
1902     auto HasNoConstOp = [](const FactOrCheck &B) {
1903       Value *V0 = B.isConditionFact() ? B.Cond.Op0 : B.Inst->getOperand(0);
1904       Value *V1 = B.isConditionFact() ? B.Cond.Op1 : B.Inst->getOperand(1);
1905       return !isa<ConstantInt>(V0) && !isa<ConstantInt>(V1);
1906     };
1907     // If both entries have the same In numbers, conditional facts come first.
1908     // Otherwise use the relative order in the basic block.
1909     if (A.NumIn == B.NumIn) {
1910       if (A.isConditionFact() && B.isConditionFact()) {
1911         bool NoConstOpA = HasNoConstOp(A);
1912         bool NoConstOpB = HasNoConstOp(B);
1913         return NoConstOpA < NoConstOpB;
1914       }
1915       if (A.isConditionFact())
1916         return true;
1917       if (B.isConditionFact())
1918         return false;
1919       auto *InstA = A.getContextInst();
1920       auto *InstB = B.getContextInst();
1921       return InstA->comesBefore(InstB);
1922     }
1923     return A.NumIn < B.NumIn;
1924   });
1925 
1926   SmallVector<Instruction *> ToRemove;
1927 
1928   // Finally, process ordered worklist and eliminate implied conditions.
1929   SmallVector<StackEntry, 16> DFSInStack;
1930   SmallVector<ReproducerEntry> ReproducerCondStack;
